import{_ as e,c as l,o as i,ah as r}from"./chunks/framework.Cnj7lwEt.js";const p=JSON.parse('{"title":"Next.js","description":"","frontmatter":{},"headers":[],"relativePath":"github汇总/Web框架/Next.js-Web框架.md","filePath":"github汇总/Web框架/Next.js-Web框架.md"}'),t={name:"github汇总/Web框架/Next.js-Web框架.md"};function h(o,a,n,s,c,d){return i(),l("div",null,a[0]||(a[0]=[r('<h1 id="next-js" tabindex="-1">Next.js <a class="header-anchor" href="#next-js" aria-label="Permalink to “Next.js”">​</a></h1><h2 id="作者或组织名" tabindex="-1">作者或组织名 <a class="header-anchor" href="#作者或组织名" aria-label="Permalink to “作者或组织名”">​</a></h2><p>Vercel</p><h2 id="项目类别" tabindex="-1">项目类别 <a class="header-anchor" href="#项目类别" aria-label="Permalink to “项目类别”">​</a></h2><p>Web框架</p><h2 id="核心痛点" tabindex="-1">核心痛点 <a class="header-anchor" href="#核心痛点" aria-label="Permalink to “核心痛点”">​</a></h2><p>用React构建应用需要自己配置webpack、Babel等工具，处理路由、服务端渲染等复杂问题</p><h2 id="主要功能" tabindex="-1">主要功能 <a class="header-anchor" href="#主要功能" aria-label="Permalink to “主要功能”">​</a></h2><ul><li>React框架，用于构建全栈Web应用</li><li>文件系统路由</li><li>服务端渲染（SSR）</li><li>静态生成（SSG）</li><li>增量静态再生成（ISR）</li><li>API路由</li><li>React Server Components支持</li><li>部分预渲染（PPR）</li><li>TurboPack构建工具</li><li>内置图像优化、字体优化、脚本优化</li><li>配合Vercel一键部署</li><li>完善的文档和丰富的学习资源</li></ul><h2 id="项目亮点" tabindex="-1">项目亮点 <a class="header-anchor" href="#项目亮点" aria-label="Permalink to “项目亮点”">​</a></h2><ul><li>Vercel官方开发，品质有保障</li><li>基于React，学习曲线平滑</li><li>文件系统路由，简单直观</li><li>支持服务端渲染、静态生成、增量静态再生成</li><li>支持React Server Components，减少客户端JavaScript</li><li>最新版本支持部分预渲染和TurboPack构建工具，速度快</li><li>内置图像优化、字体优化、脚本优化，性能好</li><li>配合Vercel一键部署，也可部署到其他平台</li><li>完善的文档和丰富的学习资源</li><li>活跃的社区</li><li>GitHub上超高Stars，最受欢迎的React框架之一</li></ul><h2 id="荣誉信息" tabindex="-1">荣誉信息 <a class="header-anchor" href="#荣誉信息" aria-label="Permalink to “荣誉信息”">​</a></h2><p>README/仓库信息中未明确说明</p><h2 id="项目地址" tabindex="-1">项目地址 <a class="header-anchor" href="#项目地址" aria-label="Permalink to “项目地址”">​</a></h2><p><a href="https://github.com/vercel/next.js" target="_blank" rel="noreferrer">https://github.com/vercel/next.js</a> <a href="/网络环境.html">海外网络环境配置 →</a></p><h2 id="安装或部署教程" tabindex="-1">安装或部署教程 <a class="header-anchor" href="#安装或部署教程" aria-label="Permalink to “安装或部署教程”">​</a></h2><h3 id="教程适用对象与环境范围" tabindex="-1">教程适用对象与环境范围 <a class="header-anchor" href="#教程适用对象与环境范围" aria-label="Permalink to “教程适用对象与环境范围”">​</a></h3><p>适用于Web开发者，支持Node.js环境</p><h3 id="前置条件检查" tabindex="-1">前置条件检查 <a class="header-anchor" href="#前置条件检查" aria-label="Permalink to “前置条件检查”">​</a></h3><ol><li>系统要求：支持Windows、macOS、Linux</li><li>Node.js版本：Node.js 18.17或更高版本 <ul><li>检查命令：<code>node --version</code></li><li>通过标准：版本号≥18.17</li></ul></li><li>npm/pnpm/yarn包管理器 <ul><li>检查命令：<code>npm --version</code></li><li>通过标准：包管理器正常可用</li></ul></li><li>网络连接：可访问互联网</li></ol><h3 id="主路径-创建新项目" tabindex="-1">主路径：创建新项目 <a class="header-anchor" href="#主路径-创建新项目" aria-label="Permalink to “主路径：创建新项目”">​</a></h3><h4 id="步骤1-创建next-js项目" tabindex="-1">步骤1：创建Next.js项目 <a class="header-anchor" href="#步骤1-创建next-js项目" aria-label="Permalink to “步骤1：创建Next.js项目”">​</a></h4><ul><li>步骤目标：使用官方脚手架创建新项目</li><li>执行位置：终端/命令行</li><li>完整命令：<code>npx create-next-app@latest</code></li><li>成功标志：项目创建成功，进入项目目录</li><li>失败处理：检查Node.js版本是否符合要求，网络连接是否正常</li></ul><h4 id="步骤2-运行开发服务器" tabindex="-1">步骤2：运行开发服务器 <a class="header-anchor" href="#步骤2-运行开发服务器" aria-label="Permalink to “步骤2：运行开发服务器”">​</a></h4><ul><li>步骤目标：启动开发服务器</li><li>执行位置：项目目录</li><li>完整命令：<code>npm run dev</code></li><li>成功标志：服务器启动成功，可访问<a href="http://localhost:3000" target="_blank" rel="noreferrer">http://localhost:3000</a></li><li>失败处理：检查端口3000是否被占用，查看错误日志</li></ul><h3 id="安装成功验证" tabindex="-1">安装成功验证 <a class="header-anchor" href="#安装成功验证" aria-label="Permalink to “安装成功验证”">​</a></h3><ol><li>访问地址：<a href="http://localhost:3000" target="_blank" rel="noreferrer">http://localhost:3000</a></li><li>官方文档：<a href="https://nextjs.org/docs" target="_blank" rel="noreferrer">https://nextjs.org/docs</a> <a href="/网络环境.html">海外网络环境配置 →</a></li></ol><h3 id="常见错误排查" tabindex="-1">常见错误排查 <a class="header-anchor" href="#常见错误排查" aria-label="Permalink to “常见错误排查”">​</a></h3><ol><li>现象：项目创建失败 <ul><li>可能原因：Node.js版本过低或网络问题</li><li>解决步骤：升级Node.js到18.17或更高版本，检查网络连接</li></ul></li><li>现象：开发服务器启动失败 <ul><li>可能原因：端口占用或依赖问题</li><li>解决步骤：检查端口3000是否被占用，重新安装依赖</li></ul></li><li>现象：构建失败 <ul><li>可能原因：代码错误或配置问题</li><li>解决步骤：检查代码语法，查看构建日志</li></ul></li></ol><h3 id="信息缺失说明" tabindex="-1">信息缺失说明 <a class="header-anchor" href="#信息缺失说明" aria-label="Permalink to “信息缺失说明”">​</a></h3><p>如需深入了解详细功能和使用方法，可访问官方文档：<a href="https://nextjs.org/docs" target="_blank" rel="noreferrer">https://nextjs.org/docs</a> <a href="/网络环境.html">海外网络环境配置 →</a></p>',31)]))}const x=e(t,[["render",h]]);export{p as __pageData,x as default};
